#[allow(dead_code)]
#[allow(clippy::too_many_arguments)]
fn order_imm_op(
    state: &mut LuaState,
    cl: &lua_types::GcRef<lua_types::LuaLClosure>,
    pc: &mut u32,
    trap: &mut bool,
    ci: CallInfoIdx,
    base: StackIdx,
    i: Instruction,
    opi: fn(i64, i64) -> bool,
    opf: fn(f64, f64) -> bool,
    inv: bool,
    tm: TagMethod,
