impl InstructionExt for Instruction {
    fn opcode(&self) -> OpCode {
        match self.raw() & 0x7F {
            0  => OpCode::Move,
            1  => OpCode::LoadI,
            2  => OpCode::LoadF,
            3  => OpCode::LoadK,
            4  => OpCode::LoadKX,
            5  => OpCode::LoadFalse,
