fn order_imm_op(
    state: &mut LuaState,
    cl: &lua_types::GcRef<lua_types::LuaLClosure>,
    pc: &mut u32,
    trap: &mut bool,
    ci: CallInfoIdx,
    base: StackIdx,
    i: Instruction,
    opi: fn(i64, i64) -> bool,
    opf: fn(f64, f64) -> bool,
    inv: bool,
    tm: TagMethod,
) -> Result<(), LuaError> {
    let ra_v = state.get_at(base + i.arg_a()).clone();
    let im = i.arg_s_b() as i64;
