                    OpCode::NewTable => {
                        let ra = base + i.arg_a();
                        let mut b = i.arg_b();
                        let mut c = i.arg_c();
                        if b > 0 {
                            b = 1 << (b - 1); // C: b = 1 << (b - 1)
                        }
                        if i.test_k() {
                            let extra = state.proto_code(&cl, pc);
                            pc += 1;
                            // C: c += GETARG_Ax(*pc) * (MAXARG_C + 1)
                            const MAXARG_C: i32 = (1 << 8) - 1;
                            c += extra.arg_ax() * (MAXARG_C + 1);
                        } else {
                            pc += 1; // skip extra argument even if zero
                        }
